// Microcontroller version (Arduino / ESP32)

#include <Arduino.h>

// ----- CONFIG -----
const int sensorPin = A0;            // Input pin from the crystal
const int stimulusPin = 9;           // Output pin for stimulus (e.g., signal pulse)
const int readInterval = 100;        // Time between readings (ms)
const int readingWindow = 5000;      // How long to observe after a stimulus (ms)
const int numSamples = readingWindow / readInterval;

// ----- STATE -----
float signalHistory[50];            // Rolling buffer
int currentIndex = 0;
bool observing = false;
unsigned long stimulusTime = 0;

// ----- SETUP -----
void setup() {
  Serial.begin(9600);
  pinMode(sensorPin, INPUT);
  pinMode(stimulusPin, OUTPUT);
  Serial.println("Crystal Comm Engine Ready.");
}

// ----- FUNCTION: Apply Stimulus -----
void applyStimulus() {
  digitalWrite(stimulusPin, HIGH);
  delay(200); // Send a short pulse
  digitalWrite(stimulusPin, LOW);
  stimulusTime = millis();
  observing = true;
  currentIndex = 0;
  Serial.println("Stimulus sent. Observing response...");
}

// ----- FUNCTION: Analyze Response -----
void analyzeResponse() {
  float minVal = 1024;
  float maxVal = 0;
  float sum = 0;

  for (int i = 0; i < numSamples; i++) {
    float val = signalHistory[i];
    sum += val;
    if (val > maxVal) maxVal = val;
    if (val < minVal) minVal = val;
  }

  float avg = sum / numSamples;
  float delta = maxVal - minVal;

  Serial.print("Response delta: "); Serial.println(delta);

  // Interpret pattern
  if (delta > 150) {
    Serial.println(">> Response: Strong reaction. Interpreted as YES or EXCITEMENT.");
  } else if (delta > 60) {
    Serial.println(">> Response: Mild fluctuation. Interpreted as CURIOUS or UNSURE.");
  } else if (delta < 20) {
    Serial.println(">> Response: Flatline. Interpreted as NO or SILENCE.");
  } else {
    Serial.println(">> Response: Ambiguous. Interpreted as UNCLEAR.");
  }

  observing = false;
}

// ----- MAIN LOOP -----
void loop() {
  if (Serial.available()) {
    char input = Serial.read();
    if (input == 'p') { // Press 'p' in serial to pulse
      applyStimulus();
    }
  }

  if (observing) {
    if (currentIndex < numSamples) {
      float val = analogRead(sensorPin);
      signalHistory[currentIndex++] = val;
      delay(readInterval);
    } else {
      analyzeResponse();
    }
  }
}"
