class CodeRepairEngine:
    def __init__(self, module_path, protected_keywords=None, log_path='sedona_repair_log.json'):
        self.module_path = module_path
        self.log_path = log_path
        self.module_name = os.path.splitext(os.path.basename(module_path))[0]
        self.protected_keywords = protected_keywords or ["morality", "core_emotion", "security"]
        self.repair_log = []
        self.syntax_reference = self.load_python_reference()

    def load_python_reference(self):
        return {
            "IndentationError": "Ensure consistent use of spaces or tabs. Mixing causes failure.",
            "SyntaxError": "Check for missing colons after if/elif/else, def, class. Ensure all parentheses are closed.",
            "NameError": "This usually indicates a variable or function is used before it's defined.",
            "def": "Functions must be declared as: def name(params): followed by an indented block.",
            "class": "Classes must begin with: class Name(Base): and follow with an indented body.",
            "lambda": "Lambda expressions are: lambda args: expression.",
            "import": "Use correct import syntax. Do not comment out active import lines.",
            "return": "Ensure return statements are inside function blocks and properly indented."
        }

    def lookup_syntax_reference(self, keyword):
        return self.syntax_reference.get(keyword, "No reference found for this term.")

    def run_test(self, test_function_name):
        try:
            module = importlib.import_module(self.module_name)
            getattr(module, test_function_name)()
            return True, "Test passed."
        except Exception as e:
            return False, traceback.format_exc()

    def can_edit(self):
        with open(self.module_path, 'r', encoding='utf-8') as f:
            content = f.read().lower()
            if any(kw in content for kw in self.protected_keywords):
                return False
        return True

    def suggest_fix(self, error_trace):
        for key in self.syntax_reference:
            if key.lower() in error_trace.lower():
                return self.lookup_syntax_reference(key)
        return "Suggestion: Error not found in local reference index. Manual review recommended."

    def attempt_repair(self, test_function_name):
        success, message = self.run_test(test_function_name)
        if success:
            return self.log_attempt("Test passed. No repair needed.", success=True)

        if not self.can_edit():
            suggestion = self.suggest_fix(message)
            return self.log_attempt(f"RESTRICTED MODULE. Cannot self-repair. {suggestion}", success=False, restricted=True, trace=message)

        try:
            with open(self.module_path, 'r', encoding='utf-8') as f:
                lines = f.readlines()

            modified = False
            repaired_lines = []
            for line in lines:
                original_line = line
                if 'import ' in line and '#' in line:
                    line = line.split('#')[0].strip() + '\n'
                    modified = True
                if 'print(' in line and not line.strip().endswith(')'):
                    line = line.strip() + ')\n'
                    modified = True
                if re.match(r'\s*(if|elif|else|for|while|def|class)\s+.*[^:](\s*)$', line):
                    line = line.strip() + ':\n'
                    modified = True
                if '\t' in line:
                    line = line.replace('\t', '    ')
                    modified = True
                if re.search(r"NameError: name '(\w+)' is not defined", message):
                    var_name = re.search(r"name '(\w+)'", message).group(1)
                    if f'{var_name} =' not in ''.join(lines):
                        repaired_lines.insert(0, f'{var_name} = None  # Auto-initialized\n')
                        modified = True
                repaired_lines.append(line)

            if modified:
                with open(self.module_path, 'w', encoding='utf-8') as f:
                    f.writelines(repaired_lines)
                importlib.reload(importlib.import_module(self.module_name))
                return self.log_attempt("Self-repair completed with extended corrections.", success=True)
            else:
                return self.log_attempt("Attempted repair but no known issues matched.", success=False, trace=message)

        except Exception as e:
            return self.log_attempt("Self-repair failed during extended code modification.", success=False, trace=traceback.format_exc())

    def log_attempt(self, note, success=False, restricted=False, trace=None):
        entry = {
            "note": note,
            "success": success,
            "restricted": restricted,
            "traceback": trace
        }
        self.repair_log.append(entry)
        with open(self.log_path, 'w', encoding='utf-8') as f:
            json.dump(self.repair_log, f, indent=4)
        return entry
